+
+  } else {
+    boost::asio::serial_port *serial = new boost::asio::serial_port(io_service);
+    handle.reset(serial);
+
+    // open serial port
+    try {
+      serial->open(device);
+    } catch(std::runtime_error& e) {
+      ROS_ERROR("Could not open serial port %s: %s", device.c_str(), e.what());
+      delete serial;
+      return 1;
+    }
