+  poller = nh->createTimer(ros::Duration(1.0), &pollMessages);
+  poller.start();
+
+  // wait...
+  ros::spin();
+
+  // cleanup
+cleanup:
+  gps.close();
+  handle.reset();
+  ROS_INFO("Closed connection to %s.", device.c_str());
+
+  delete nh;
+  return 0;
+}

